/// Pre-processes XML content to resolve external entity declarations and references.
/// This manually handles entity resolution since xml-rs doesn't natively expand external entities.
fn preprocess_xml_entities(xml_content: &str) -> Result<String, String> {
    let mut entity_map: HashMap<String, String> = HashMap::new();
    let mut processed = xml_content.to_string();

    // Parse ENTITY declarations from DOCTYPE
    // Matches: <!ENTITY name SYSTEM "uri">
    let entity_pattern = regex::Regex::new(
        r#"<!ENTITY\s+(\w+)\s+SYSTEM\s+"([^"]+)"\s*>"#
    ).map_err(|e| format!("Regex error: {}", e))?;

    for cap in entity_pattern.captures_iter(xml_content) {
        let entity_name = &cap[1];
        let system_id = &cap[2];

        let content = resolve_external_entity(system_id)?;
        entity_map.insert(entity_name.to_string(), content);
    }

    // Also handle PUBLIC entities
    let public_entity_pattern = regex::Regex::new(
        r#"<!ENTITY\s+(\w+)\s+PUBLIC\s+"[^"]*"\s+"([^"]+)"\s*>"#
    ).map_err(|e| format!("Regex error: {}", e))?;

    for cap in public_entity_pattern.captures_iter(xml_content) {
        let entity_name = &cap[1];
        let system_id = &cap[2];

        let content = resolve_external_entity(system_id)?;
        entity_map.insert(entity_name.to_string(), content);
    }

    // Replace entity references &name; with resolved content
    for (name, value) in &entity_map {
        let reference = format!("&{};", name);
        processed = processed.replace(&reference, value);
    }

    // Remove the DOCTYPE declaration to avoid parser issues after substitution
    let doctype_pattern = regex::Regex::new(r"<!DOCTYPE[^>]*>")
        .map_err(|e| format!("Regex error: {}", e))?;
    processed = doctype_pattern.replace_all(&processed, "").to_string();

    Ok(processed)
}

